import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip, CircularProgress } from '@mui/material';
import { Info } from '@mui/icons-material';
import response from './response.json';

interface SecurityScore {
  score: number;
  grade: string;
}

interface PasswordDetails {
  totalPasswords: number;
  weakPasswords: number;
  reusedPasswords: number;
}

interface WidgetData {
  securityScore: SecurityScore;
  passwordDetails: PasswordDetails;
}

export default function Widget() {
  const widgetData = response.data as WidgetData;
  const { securityScore, passwordDetails } = widgetData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 400, bgcolor: '#1E1E1E', color: '#FFFFFF' }} elevation={3}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 1 }}>
              Password Health
            </Typography>
            <Box sx={{ display: 'flex', alignItems: 'center' }}>
              <CircularProgress variant="determinate" value={securityScore.score} size={50} sx={{ color: response.meta.primaryColor, mr: 2 }} />
              <Box>
                <Typography variant="h4" fontWeight={700} sx={{ color: response.meta.primaryColor }}>
                  {securityScore.score}
                </Typography>
                <Typography variant="body2" color="text.secondary">
                  Grade: {securityScore.grade}
                </Typography>
              </Box>
            </Box>
          </Box>

          <Box>
            <Typography variant="body2" sx={{ mb: 1 }}>
              Password Details
            </Typography>
            <Stack direction="row" spacing={0.5}>
              <Chip label={`Total: ${passwordDetails.totalPasswords}`} sx={{ fontSize: '11px', bgcolor: '#424242', color: '#FFFFFF' }} />
              <Chip label={`Weak: ${passwordDetails.weakPasswords}`} sx={{ fontSize: '11px', bgcolor: '#424242', color: '#FFFFFF' }} />
              <Chip label={`Reused: ${passwordDetails.reusedPasswords}`} sx={{ fontSize: '11px', bgcolor: '#424242', color: '#FFFFFF' }} />
            </Stack>
          </Box>

          <Box sx={{ display: 'flex', alignItems: 'center', mt: 2 }}>
            <Info sx={{ fontSize: 20, color: response.meta.accentColor, mr: 1 }} />
            <Typography variant="caption" color="text.secondary">
              Improve your password health by updating weak and reused passwords.
            </Typography>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
